(function(){
  try {
    var text = document.body.innerText;
    var result = {};
    var m;
    m = text.match(/春季|夏季|秋季|冬季/);
    if (m) result.season = m[0];
    m = text.match(/第\s*([0-9]+)\s*天/);
    if (m) result.day = parseInt(m[1]);
    m = text.match(/([0-9]+)\s*元/);
    if (m) result.money = parseInt(m[1]);
    m = text.match(/⚡\s*([0-9]+)\s*\/\s*200/);
    if (m) result.stamina = parseInt(m[1]);
    m = text.match(/❤️\s*([0-9]+)\s*\/\s*200/);
    if (m) result.health = parseInt(m[1]);
    m = text.match(/水稻[：:]\s*([0-9]+)/);
    if (m) result.rice = parseInt(m[1]);
    m = text.match(/红薯[：:]\s*([0-9]+)/);
    if (m) result.sweet = parseInt(m[1]);
    m = text.match(/(小雨|中雨|大雨|晴|阴|多云|雪|雾)/);
    if (m) result.weather = m[1];
    result.maxStamina = 200;
    result.maxHealth = 200;
    return JSON.stringify(result);
  } catch(e) {
    return JSON.stringify({error: e.message});
  }
})()
